<template>
  <div id="app" @click="updateIdle">
    <Main :version="version"></Main>
  </div>
</template>

<script>
import { publicPath } from '../vue.config'
import Main from './components/Main.vue'
import { DateTime } from "luxon";
import 'axios';
import axios from 'axios';

const maxIdleSeconds = 60 * 30;

export default {
  name: 'App',
  data: function() {
    return {
      lastInput: null,
      version: ''
    }
  },
  components: {
    Main
  },
  methods: {
    updateIdle() {
      this.lastInput = DateTime.now().toSeconds();
    },
    async getVersion() {
      var version = '';
      var versionUrl = `${location.origin}${publicPath}version.html`;
      try {
        version = (await axios.get(versionUrl)).data.trim();
      }
      catch (err) {
        console.error(err);
      }
      return version;
    }
  },
  async mounted() {
    this.version = (await this.getVersion());

    this.updateIdle();
    setInterval(async () => {
      if ((DateTime.now().toSeconds() - this.lastInput) >= (maxIdleSeconds - 5)) {
        if (window.navigator.onLine) {
          const version = await this.getVersion();
          if (version != this.version) {
            location.reload();
          }
        }
      }
    }, 1000 * maxIdleSeconds);
  }
}
</script>

