<template>
  <tr :class="getHidden">
    <td class="gear-slot">
      <img :src="getIcon" onerror="this.src='data:image/gif;base64,R0lGODlhAQABAAD/ACwAAAAAAQABAAACADs='">
      <a :href="getId" target="_blank"><span>{{ getName }}</span></a>
    </td>
    <td :class="getTier">{{ getAmount }}</td>
  </tr>
</template>

<script>

export default {
  name: 'ResolveGearItem',
  props: {
    title: String,
    itemSlot: String,
    resolveGear: Object
  },
  data: function() {
    return {
      showing: true
    }
  },
  computed: {
    getHidden() {
      if (this.getResolveAmount() > 0) {
          return '';
      }
      return 'hidden';
    },
    getAmount() {
      return this.getResolveAmount();
    },
    getTier() {
      if (Object.prototype.hasOwnProperty.call(this.resolveGear, this.itemSlot)) {
        return this.resolveGear[this.itemSlot].tier;
      }
      return '';
    },
    getId() {
      if (Object.prototype.hasOwnProperty.call(this.resolveGear, this.itemSlot)) {
        return `https://u.eq2wire.com/item/index/${this.resolveGear[this.itemSlot].id}`;
      }
      return '#';
    },
    getIcon() {
      if (Object.prototype.hasOwnProperty.call(this.resolveGear, this.itemSlot)) {
        return `https://eq2reappapi.mooo.com/icons/${this.resolveGear[this.itemSlot].iconId}.png`;
      }
      return 'data:image/gif;base64,R0lGODlhAQABAAD/ACwAAAAAAQABAAACADs=';
    },
    getName() {
      if (Object.prototype.hasOwnProperty.call(this.resolveGear, this.itemSlot)) {
        return this.resolveGear[this.itemSlot].name;
      }
      return '';
    },
  },
  methods: {
    getResolveAmount() {
      if (Object.prototype.hasOwnProperty.call(this.resolveGear, this.itemSlot)) {
        return this.resolveGear[this.itemSlot].amount;
      }
      return 0;
    }
  }
}
</script>

