<template>
  <div>
    <div class="row">
      <div class="col-md-9 col-lg-6">
        <h2>Find Characters</h2>
        <CharSelector @apiError="apiError" @charFound="charFound">
        </CharSelector>
        <div v-if="searchMessage" class="alert alert-warning">
          {{ searchMessage }}
        </div>
      </div>
    </div>
    <div v-if="searchChar" class="row">
      <div class="col">
        <CharStatsPreview
          :char="searchChar"
          :showAdd="true"
          @addGroup="addToGroup">
        </CharStatsPreview>
      </div>
    </div>
    <div class="row">
      <div class="col">
        <h2>Group</h2>
        <div
          v-if="message"
          class="alert alert-success alert-dismissible fade show">
          {{ message }}
          <button
            type="button"
            class="btn-close"
            aria-label="Close"
            @click="message = ''">
          </button>
        </div>
      </div>
    </div>

    <!-- Options -->
    <div class="accordion" id="optionsAccordion">
      <div class="accordion-item">
        <h3 class="accordion-header" id="headingOne">
          <button
            class="accordion-button collapsed"
            type="button"
            data-bs-toggle="collapse"
            data-bs-target="#collapseOne"
            aria-expanded="true"
            aria-controls="collapseOne">
            Options
          </button>
        </h3>
        <div
          id="collapseOne"
          class="accordion-collapse collapse"
          aria-labelledby="headingOne"
          data-bs-parent="#optionsAccordion">
          <div class="accordion-body">

            <div class="row">
              <div class="col-md-6">

                <!-- Show resolve -->
                <div class="option-section">
                  <div class="h5">Show resolve for</div>
                  <div class="resolve-checks">
                    <div class="form-check">
                      <input
                        class="form-check-input"
                        type="checkbox"
                        v-model="showResolveWeapons"
                        id="showResolveWeapons"/>
                      <label class="form-check-label" for="showResolveWeapons">Weapons</label>
                    </div>
                    <div class="form-check">
                      <input
                        class="form-check-input"
                        type="checkbox"
                        v-model="showResolveGear"
                        id="showResolveGear"/>
                      <label class="form-check-label" for="showResolveGear">Gear</label>
                    </div>
                    <div class="form-check">
                      <input
                        class="form-check-input"
                        type="checkbox"
                        v-model="showResolveJewelry"
                        id="showResolveJewelry"/>
                      <label class="form-check-label" for="showResolveJewelry">Jewelry</label>
                    </div>
                    <div class="form-check">
                      <input
                        class="form-check-input"
                        type="checkbox"
                        v-model="showResolveExtra"
                        id="showResolveExtra"/>
                      <label class="form-check-label" for="showResolveExtra">Extra</label>
                    </div>
                  </div>
                </div>

                <!-- Compare -->
                <div class="option-section">
                  <div class="h5">Compare</div>
                  <div class="compare-actions">
                    <div class="form-check">
                      <input
                        class="form-check-input"
                        type="checkbox"
                        v-model="showCompare"
                        id="showCompare"/>
                      <label class="form-check-label" for="showCompare">Select characters</label>
                    </div>
                    <button
                      v-if="comparePossible"
                      type="button"
                      class="btn btn-primary"
                      ref="btnCompare"
                      @click="doCompare">
                      Compare
                    </button>
                  </div>
                </div>

              </div>

              <div class="col-md-6">

                <!-- Save -->
                <div class="option-section">
                  <div class="h5">Save</div>
                  <div class="input-group">
                    <input type="text" class="form-control" placeholder="Group name" v-model.trim="groupSaveName">
                    <button class="btn btn-primary" type="button" @click="saveGroup">Save group</button>
                  </div>
                </div>

                <!-- Load -->
                <div class="option-section">
                  <div class="h5">Load</div>
                  <div class="input-group">
                    <select id="load" class="form-select" v-model="groupLoad">
                      <option v-for="save in getSortedGroupSaves" :value="save.key" :key="save.key">{{ save.name }}</option>
                    </select>
                    <button class="btn btn-primary" type="button" @click="loadGroup">Load group</button>
                    <button class="btn btn-secondary" type="button" @click="removeGroup">Remove group</button>
                  </div>
                </div>

              </div>
            </div>
          </div>
        </div>
      </div>
    </div>

    <!-- Sort -->
    <div class="option-section">
      <label for="sort" class="col-form-label">Sort by</label>
      <select id="sort" class="form-select" v-model.trim="sort">
        <option value="name">Name</option>
        <option value="resolve">Resolve</option>
        <option value="potency">Potency</option>
        <option value="cb">Crit Bonus</option>
        <option value="fervor">Fervor</option>
      </select>
    </div>

    <div v-for="char in getSortedChars" v-bind:key="char.id" class="row">
      <div class="col">
        <CharStatsPreview
          :char="char"
          :showRemove="true"
          :showCompare="showCompare"
          :disableCompare="disableCompare"
          :showResolveWeapons="showResolveWeapons"
          :showResolveGear="showResolveGear"
          :showResolveJewelry="showResolveJewelry"
          :showResolveExtra="showResolveExtra"
          @removeGroup="removeFromGroup"
          @addCompare="addToCompare"
          @removeCompare="removeFromCompare">
        </CharStatsPreview>
      </div>
    </div>
  </div>
</template>

<script>
import { publicPath } from "../../vue.config";
import { getPlayerStatsById } from "@/util/api";
import CharSelector from "./CharSelector.vue";
import CharStatsPreview from "./CharStatsPreview.vue";

export default {
  name: "Group",
  components: {
    CharSelector,
    CharStatsPreview,
  },
  data: function () {
    return {
      searchChar: null,
      searchMessage: "",
      chars: [],
      message: "Loading...",
      sort: "",
      showResolveWeapons: false,
      showResolveGear: false,
      showResolveJewelry: false,
      showResolveExtra: false,
      showCompare: false,
      disableCompare: false,
      compareChars: [],
      groupSaveName: '',
      groupSaves: [],
      groupLoad: null
    };
  },
  props: ["players"],
  mounted: async function () {
    await this.parsePlayers();
    this.initGroupSaves();
  },
  watch: {
    $route: async function () {
      await this.parsePlayers();
      this.initGroupSaves();
    },
  },
  computed: {
    getSortedChars: function () {
      let sorted = [...this.chars];
      switch (this.sort) {
        case "name":
          sorted.sort((x, y) => {
            return x.name.localeCompare(y.name);
          });
          break;
        case "resolve":
          sorted.sort((x, y) => {
            return y.resolve.total > x.resolve.total ? 1 : -1;
          });
          break;
        case "potency":
          sorted.sort((x, y) => {
            return y.potency.total > x.potency.total ? 1 : -1;
          });
          break;
        case "cb":
          sorted.sort((x, y) => {
            return y.cb.total > x.cb.total ? 1 : -1;
          });
          break;
        case "fervor":
          sorted.sort((x, y) => {
            return y.fervor.total > x.fervor.total ? 1 : -1;
          });
          break;
      }
      return sorted;
    },
    comparePossible() {
      return this.showCompare && this.compareChars.length >= 2;
    },
    getSortedGroupSaves() {
      const saves = [...this.groupSaves];
      saves.sort((a, b) => {
        return a.name.localeCompare(b.name);
      });
      return saves;
    }
  },
  methods: {
    parsePlayers: async function () {
      var playerIds = [];
      var input = [];
      if (typeof this.players == "string") {
        input = this.players.split(/[^\d]/);
      } else if (Array.isArray(this.players)) {
        input = this.players;
      }
      input.forEach((item) => {
        const player = parseInt(item);
        if (Number.isInteger(player)) {
          playerIds.push(player);
        }
      });

      await this.loadPlayers(playerIds);
    },
    loadPlayers: async function (playerIds) {
      if (playerIds.length > 0) {
        this.updateTitle("Loading...");
        var loadingChars = [];
        for (const playerId of playerIds) {
          loadingChars.push(getPlayerStatsById(playerId));
        }
        Promise.all(loadingChars).then((values) => {
          this.chars = values;
          this.message = "";
        })
        .catch((err) => {
          this.chars = [];
          this.message = "Error while loading.";
          console.error(err);
        });
        this.updateTitle();
        this.updateLink();
      } else {
        this.message = "No characters added yet.";
      }
    },
    charFound: function (charInfo) {
      this.searchMessage = "";
      if (charInfo.char) {
        this.searchChar = charInfo.char;
      } else {
        this.searchMessage = `Could not find ${charInfo.charName}`;
      }
    },
    apiError: function () {
      this.$emit("apiError");
    },
    addToGroup(char) {
      if (char != null) {
        for (const existing of this.chars) {
          if (existing.id == char.id) {
            return;
          }
        }

        this.chars.push(char);
        this.message = "";
        this.searchChar = null;
        this.updateTitle();
        this.updateLink();
      }
    },
    removeFromGroup(char) {
      if (char != null) {
        var index = -1;
        for (var i = 0; i < this.chars.length; i++) {
          if (this.chars[i].id == char.id) {
            index = i;
            break;
          }
        }
        if (index >= 0) {
          this.chars.splice(index, 1);

          this.message = "";
          this.updateTitle();
          this.updateLink();
        }
      }
    },
    addToCompare(char) {
      this.compareChars.push(char);
      this.disableCompare = this.comparePossible;
      if (this.comparePossible) {
        window.requestAnimationFrame(() => {
          let btnCompare = this.$refs.btnCompare;
          btnCompare.focus();
          console.log(btnCompare);
          window.scrollTo({
            top: btnCompare.offsetTop - 30,
            behavior: "smooth",
          });
        });
      }
    },
    removeFromCompare(char) {
      var index = -1;
      for (var i = 0; i < this.compareChars.length; i++) {
        if (this.compareChars[i].id == char.id) {
          index = i;
          break;
        }
      }
      if (index >= 0) {
        this.compareChars.splice(index, 1);
      }
      this.disableCompare = this.comparePossible;
    },
    getGroupCharIds() {
      return this.chars.map(char => { return char.id });
    },
    updateTitle: function (message) {
      if (!message) {
        const charStr = this.chars.length > 0 ? `(${this.chars.length}) ` : "";
        message = `Group ${charStr}`;
      }
      document.title = `${message} | eq2cmp`;
    },
    updateLink: function () {
      const chars = this.getGroupCharIds();
      const link =
        chars.length < 1
          ? ""
          : `${window.location.origin}${publicPath}group/${chars.join("/")}`;
      this.$emit("newLink", link);
    },
    doCompare() {
      var chars = [];
      for (var i = 0; i < this.compareChars.length; i++) {
        if (this.compareChars[i]) {
          chars.push(
            `char=${this.compareChars[i].server}.${this.compareChars[i].name}`
          );
        }
      }
      const link =
        chars.length < 1
          ? ""
          : `${window.location.origin}${publicPath}?${chars.join("&")}`;
      window.open(link, "_blank").focus();
    },
    saveGroup() {
      const groupName = this.groupSaveName;
      if (groupName.length < 1) {
        this.message = 'You must provide a group name to save as.'
      }
      else {
        const groupNameKey = 'group.' + groupName.replace(/\s/g, '');
        const groupSave = {
          key: groupNameKey,
          name: groupName,
          ids: this.getGroupCharIds()
        };

        // Check if a save already exists for this key
        var index = -1;
        for (var i = 0; i < this.groupSaves.length; i++) {
          if (this.groupSaves[i].key == groupSave.key) {
            index = i;
            break;
          }
        }
        if (index >= 0) {
          this.groupSaves.splice(index, 1);
        }

        this.groupSaves.push(groupSave);

        localStorage.setItem(groupNameKey, JSON.stringify(groupSave));
        localStorage.setItem('group.__keys', JSON.stringify(this.groupSaves.map(save => { return save.key})));
      }
    },
    loadGroup() {
      const group = this.groupSaves.find(item => {
        return item.key == this.groupLoad;
      });
      if (group) {
        const playerIds = group.ids || [];
        this.message = `Loading ${playerIds.length} character${playerIds.length == 1 ? '' : 's'}`;
        this.loadPlayers(playerIds);
      }
    },
    removeGroup() {
      const group = this.groupSaves.find(item => {
        return item.key == this.groupLoad;
      });
      if (group) {
        // Check if a save already exists for this key
        var index = -1;
        for (var i = 0; i < this.groupSaves.length; i++) {
          if (this.groupSaves[i].key == group.key) {
            index = i;
            break;
          }
        }
        if (index >= 0) {
          this.groupSaves.splice(index, 1);
          localStorage.removeItem(group.key);
        }
      }
    },
    initGroupSaves() {
      this.groupSaves.splice(0, this.groupSaves.length);

      let keys = localStorage.getItem('group.__keys');
      if (keys) {
        keys = JSON.parse(keys);
        keys.forEach(key => {
          let groupSave = localStorage.getItem(key);
          if (groupSave) {
            this.groupSaves.push(JSON.parse(groupSave));
          }
        });
      }
    }
  },
};
</script>

